use crate::codec::tss::decode_tss_message;
use crate::codec::xrpl::decode_prices_from_encoded_tx;

pub fn verify_message(encoded_tx: &[u8], tss_message: &[u8]) -> Result<(), anyhow::Error> {
    let tx_prices = decode_prices_from_encoded_tx(encoded_tx)?;
    let tss_message = decode_tss_message(tss_message)?;

    let signal_prices = tss_message.signal_prices()?;

    if tx_prices != signal_prices {
        return Err(anyhow::anyhow!(
            "Prices do not match: tx_signal_prices={:?}, tss_signal_prices={:?}",
            tx_prices,
            signal_prices
        ));
    }
    Ok(())
}

#[cfg(test)]
mod integration_tests {
    use super::*;
    use hex::decode;

    #[test]
    fn test_verify_message_xrpl_vs_tss() {
        // 1. XRPL Encoded Transaction (Hex)
        let encoded_tx_hex = "";
        let encoded_tx = decode(encoded_tx_hex).expect("Invalid XRPL hex");

        // 2. TSS Message (Hex)
        let tss_message_hex = ""; // Note: Fixed potential truncated hex in example
        let tss_msg_bytes = decode(tss_message_hex).expect("Invalid TSS hex");

        // 3. Execution
        let result = verify_message(&encoded_tx, &tss_msg_bytes);

        // 4. Assertions
        assert!(result.is_ok());
    }
}
